  return String(v);
}

const sys      = norm({{ systemFilter.value }});
const area     = norm({{ areaFilter.value }});
const floor    = norm({{ floorFilter.value }});
const diam     = norm({{ diameterFilter.value }});
const cost     = norm({{ costCodeFilter.value }});
const matchVal = norm({{ matchStatusFilter.value }});

// 🔑 Determine which diameter field to use based on tab
const activeTab = String({{ tabSelector2.value }}).toUpperCase();

const diamField =
  activeTab === "FITTINGS"
    ? "diam_primary"
    : "diam_key";   // PIPE + VALVES

// STEP 1 — Filter rows
const filtered = data.filter(r => {
  const rSys   = String(r.system_key);
  const rArea  = String(r.area_key);
  const rFloor = String(r.floor_key);
  const rCost  = String(r.cost_code_key);
  const rMatch = String(r.match_status || "");

  const rDiam = String(r[diamField]);

  const passSys   = (sys   === "ALL" || rSys   === sys);
  const passArea  = (area  === "ALL" || rArea  === area);
  const passFloor = (floor === "ALL" || rFloor === floor);
  const passDiam  = (diam  === "ALL" || rDiam  === diam);
  const passCost  = (cost  === "ALL" || rCost  === cost);
  const passMatch = (matchVal === "ALL" || rMatch === matchVal);

  return passSys && passArea && passFloor && passDiam && passCost && passMatch;
});

// STEP 2 — Add variance fields
const withVariance = filtered.map(r => {
  const estQty = Number(r.est_qty)   || 0;
  const bimQty = Number(r.bim_qty)   || 0;
  const estLab = Number(r.est_labor) || 0;
  const bimLab = Number(r.bim_labor) || 0;

  const qtyVar = estQty - bimQty;
  const labVar = estLab - bimLab;

  return {
    ...r,
    qty_variance: qtyVar,
    qty_variance_pct: estQty ? qtyVar / estQty : 0,
    labor_variance: labVar,
    labor_variance_pct: estLab ? labVar / estLab : 0
  };
});

return withVariance;
