@",null,"^1A",["^1B",["funcBody","const rows = {{ bimEstPipeComparisonData.data }} || [];

const totals = rows.reduce(
  (acc, r) => {
    const est = r.est_qty ?? 0;
    const bim = r.bim_qty ?? 0;
    const est_labor = r.est_labor ?? 0;
    const bim_labor = r.bim_labor ?? 0;

    acc.total_est_qty += est;
    acc.total_bim_qty += bim;
    acc.total_est_labor += est_labor;
    acc.total_bim_labor += bim_labor;
    acc.total_qty_variance += est - bim;

    return acc;
  },
  {
    total_est_qty: 0,
    total_bim_qty: 0,
    total_est_labor: 0,
    total_bim_labor: 0,
    total_qty_variance: 0
  }
);

return totals;
