// -----------------------------
// DATASET + FIELD ROUTING
// -----------------------------
const config = {
  Pipe: {
    filtered: {{ filteredPipeCostCodeDataTransformer.data }} || [],
    raw:      {{ bimEstPipeCostCodeComparisonData.data }} || [],
    diamField: "diam_key"
  },
  Valves: {
    filtered: {{ filteredValvesDataTransformer.data }} || [],
    raw:      {{ bimEstValvesComparisonData.data }} || [],
    diamField: "diam_key"
  },
  Fittings: {
    filtered: {{ filteredFittingsDataTransformer.data }} || [],
    raw:      {{ bimEstFittingsComparisonData.data }} || [],
    diamField: "diam_primary"
  }
};

// Fallback safety
const cfg = config[tab] || config.pipe;

// Use filtered rows if present, otherwise raw
const rows =
  cfg.filtered && cfg.filtered.length > 0
    ? cfg.filtered
    : cfg.raw;

// -----------------------------
// GENERIC DISTINCT COLLECTORS
// -----------------------------
function unique(field) {
  const set = new Set();
  rows.forEach(r => {
    if (r[field] != null && r[field] !== "") {
      set.add(String(r[field]).trim());
    }
  });
  return Array.from(set);
}

// Alphabetical sort
function sortAlpha(arr) {
  return arr.sort((a, b) => a.localeCompare(b));
}

// Numeric sort (safe)
function sortNumeric(arr) {
  return arr
    .map(v => Number(v))
    .filter(v => !Number.isNaN(v))
    .sort((a, b) => a - b);
}

// -----------------------------
// FINAL OUTPUT
// -----------------------------
return {
  systems:   ["ALL", ...sortAlpha(unique("system_key"))],
  areas:     ["ALL", ...sortAlpha(unique("area_key"))],
  floors:    ["ALL", ...sortAlpha(unique("floor_key"))],
  diameters: ["ALL", ...sortNumeric(unique(cfg.diamField))],
  costcode:  ["ALL", ...sortNumeric(unique("cost_code_key"))]
};

