^1<","function","^1=","Function","^1>",null,"^1?",null,"^1@",null,"^1A",["^1B",["funcBody","// -------------------------------------------------------
//  SELECT DATASET BASED ON TAB
// -------------------------------------------------------
let sourceRows;

switch ({{ tabSelector3.value }}) {
  case "Pipe":
    sourceRows = {{ bimEstPipeComparisonData2.data }} || [];
    break;

  case "Valves":
    sourceRows = {{ bimEstValvesComparisonData2.data }} || [];
    break;

  case "Fittings":
    sourceRows = {{ bimEstFittingsComparisonData2.data }} || [];
    break;

  default:
    sourceRows = [];
}

const rows = Array.isArray(sourceRows) ? sourceRows : [];

// -------------------------------------------------------
//  FILTER VALUES
// -------------------------------------------------------
const sys   = {{ systemFilter2.value }}   || "ALL";
const area  = {{ areaFilter2.value }}     || "ALL";
const floor = {{ floorFilter2.value }}    || "ALL";
const diam  = {{ diameterFilter2.value }} || "ALL";

// -------------------------------------------------------
//  APPLY FILTERS
// -------------------------------------------------------
const filteredRows = rows.filter(r => {
  const passSystem = (sys === "ALL" || r.system_key === sys);
  const passArea   = (area === "ALL" || r.area_key === area);
  const passFloor  = (floor === "ALL" || String(r.floor_key) === String(floor));
  const passDiam   = (diam === "ALL" || String(r.diam_key) === String(diam));

  return passSystem && passArea && passFloor && passDiam;
});

// -------------------------------------------------------
//  UTILITIES
// -------------------------------------------------------
const num = v => (v == null ? 0 : v);

function pctVar(est, bim) {
  const e = num(est);
  const b = num(bim);
  const denom = Math.abs(e) || Math.abs(b);
  if (denom === 0) return 0;
  return (e - b) / denom;
}

// -------------------------------------------------------
//  KPI OBJECT
// -------------------------------------------------------
const kpi = {
  totals: {
    est_qty: 0,
    bim_qty: 0,
    qty_variance: 0,
    qty_pct_variance: 0,

    est_labor: 0,
    bim_labor: 0,
    labor_variance: 0,
    labor_pct_variance: 0
  },

  match_status: {
    EST_ONLY: 0,
    BIM_ONLY: 0,
    MATCHED: 0,
    TOTAL_ROWS: filteredRows.length
  },

  by_system: {},
  by_area: {},
  by_floor: {},
  by_material: {},

  variance_buckets: {
    qty: { low: 0, med: 0, high: 0 },
    labor: { low: 0, med: 0, high: 0 }
  },

  top10_qty_mismatches: [],
  top10_labor_mismatches: [],

  avg_for_matches: {
    avg_qty_variance: 0,
    avg_qty_pct_variance: 0,
    avg_labor_variance: 0,
    avg_labor_pct_variance: 0,
    count: 0
  }
};

// -------------------------------------------------------
//  GROUP UTIL
// -------------------------------------------------------
function addToGroup(obj, key, r) {
  if (!obj[key]) {
    obj[key] = {
      est_qty: 0,
      bim_qty: 0,
      qty_variance: 0,

      est_labor: 0,
      bim_labor: 0,
      labor_variance: 0,

      rows: 0
    };
  }

  obj[key].est_qty += num(r.est_qty);
  obj[key].bim_qty += num(r.bim_qty);
  obj[key].qty_variance += num(r.est_qty) - num(r.bim_qty);

  obj[key].est_labor += num(r.est_labor);
  obj[key].bim_labor += num(r.bim_labor);
  obj[key].labor_variance += num(r.est_labor) - num(r.bim_labor);

  obj[key].rows++;
}

const matchRows = [];

// -------------------------------------------------------
//  PASS 1 — TOTALS & GROUPING
// -------------------------------------------------------
filteredRows.forEach(r => {
  const estQty   = num(r.est_qty);
  const bimQty   = num(r.bim_qty);
  const estLabor = num(r.est_labor);
  const bimLabor = num(r.bim_labor);

  // Totals
  kpi.totals.est_qty       += estQty;
  kpi.totals.bim_qty       += bimQty;
  kpi.totals.qty_variance  += estQty - bimQty;

  kpi.totals.est_labor     += estLabor;
  kpi.totals.bim_labor     += bimLabor;
  kpi.totals.labor_variance += estLabor - bimLabor;

  // Match status
  if (r.match_status && kpi.match_status[r.match_status] != null) {
    kpi.match_status[r.match_status]++;
  }

  if (r.match_status === "MATCH_FOUND") {
    matchRows.push(r);
  }

  // Grouping
  addToGroup(kpi.by_system, r.system_key, r);
  addToGroup(kpi.by_area,   r.area_key, r);
  addToGroup(kpi.by_floor,  String(r.floor_key), r);

  // *** UPDATED MATERIAL GROUPING — clean, correct, based on material_key ***
  const material = r.material_key ? String(r.material_key) : "UNKNOWN";
  addToGroup(kpi.by_material, material, r);
});

// -------------------------------------------------------
//  PASS 2 — TOTAL PERCENT VARIANCES
// -------------------------------------------------------
