e","","runWhenModelUpdates",false,"workflowRunExecutionType","sync","showFailureToaster",true,"query","// =============================================================================
// BIM UPLOAD HANDLER
// =============================================================================

const { access_token } = auth_state_LM.value;
if (!access_token) return { error: "Auth not ready" };

const SUPABASE_URL = "https://zwtfjmylqmfjlqadflxs.supabase.co";
const headers = {
  "apikey": retoolContext.configVars.supabaseApiKey_LM_dev,
  "Authorization": `Bearer ${access_token}`,
  "Content-Type": "application/json",
  "Prefer": "return=representation"
};

const project_id = projectDropdown.value;
const file_type = "bim";
const file = bimFileInput.value[0];

if (!project_id) return { error: "Select a project first" };
if (!file) return { error: "No file selected" };

bimuploadProgress.setValue(0);


// ─── STEP 1: Check if upload is locked ──────────────────────────────────────

const lockCheck = await fetch(
  `${SUPABASE_URL}/rest/v1/rpc/is_upload_locked`,
  {
    method: "POST",
    headers,
    body: JSON.stringify({
      p_project_id: project_id,
      p_file_type: file_type
    })
  }
).then(r => r.json());

if (lockCheck?.[0]?.locked) {
  return { error: "Another upload is in progress for this file type. Please wait." };
}

bimuploadProgress.setValue(5);


// ─── STEP 2: Create revision record (acquires the lock) ────────────────────

const revisionRes = await fetch(
  `${SUPABASE_URL}/rest/v1/revisions`,
  {
    method: "POST",
    headers,
    body: JSON.stringify({
      project_id: project_id,
      file_type: file_type,
      status: "uploading"
    })
  }
).then(r => r.json());

if (revisionRes.error || !revisionRes[0]?.revision_id) {
  bimuploadProgress.setValue(0);
  return { error: "Failed to create revision", details: revisionRes };
}

const revision_id = revisionRes[0].revision_id;

bimuploadProgress.setValue(10);


// ─── STEP 3: Parse file (CSV or XLSX) ──────────────────────────────────────

let rows;
const fileName = file.name.toLowerCase();

if (fileName.endsWith(".csv")) {
  const text = atob(file.base64Data);
  const parsed = Papa.parse(text, {
    header: true,
    skipEmptyLines: true,
    dynamicTyping: false
  });

  if (parsed.errors.length > 0) {
    bimuploadProgress.setValue(0);
    await fetch(
      `${SUPABASE_URL}/rest/v1/revisions?revision_id=eq.${revision_id}`,
      {
        method: "PATCH",
        headers,
        body: JSON.stringify({
          status: "failed",
          error_message: `CSV parse error: ${parsed.errors[0].message}`
        })
      }
    );
    return { error: "CSV parse failed", details: parsed.errors };
  }

  rows = parsed.data.map(row => ({
    ...row,
    project_id: project_id,
    revision_id: revision_id
  }));

} else if (fileName.endsWith(".xlsx") || fileName.endsWith(".xls")) {
  const workbook = XLSX.read(file.base64Data, { type: "base64" });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];

  rows = XLSX.utils.sheet_to_json(sheet, { defval: null }).map(row => {
    const cleaned = {};
    for (const [key, value] of Object.entries(row)) {
      cleaned[key.trim()] = value;
    }
    cleaned.project_id = project_id;
    cleaned.revision_id = revision_id;
    return cleaned;
  });

} else {
  bimuploadProgress.setValue(0);
  await fetch(
    `${SUPABASE_URL}/rest/v1/revisions?revision_id=eq.${revision_id}`,
    {
      method: "PATCH",
      headers,
      body: JSON.stringify({
        status: "failed",
        error_message: "Unsupported file type. Please upload .csv or .xlsx"
      })
    }
  );
  return { error: "Unsupported file type. Please upload .csv or .xlsx" };
}

if (rows.length === 0) {
  bimuploadProgress.setValue(0);
  await fetch(
    `${SUPABASE_URL}/rest/v1/revisions?revision_id=eq.${revision_id}`,
    {
      method: "PATCH",
      headers,
      body: JSON.stringify({
        status: "failed",
        error_message: "File contains no data rows"
      })
    }
  );
  return { error: "File contains no data rows" };
}

bimuploadProgress.setValue(15);


// ─── STEP 4: Batch insert into raw BIM table ───────────────────────────────

const BATCH_SIZE = 500;
const totalBatches = Math.ceil(rows.length / BATCH_SIZE);

for (let i = 0; i < rows.length; i += BATCH_SIZE) {
  const batch = rows.slice(i, i + BATCH_SIZE);
  const batchNumber = Math.floor(i / BATCH_SIZE) + 1;

  bimuploadProgress.setValue(15 + Math.round((batchNumber / totalBatches) * 65));

  const insertRes = await fetch(
    `${SUPABASE_URL}/rest/v1/all_terms_test`,
    {
      method: "POST",
      headers: {
        ...headers,
        "Prefer": "return=minimal"
      },
      body: JSON.stringify(batch)
    }
  );

  if (!insertRes.ok) {
    bimuploadProgress.setValue(0);
    await fetch(
      `${SUPABASE_URL}/rest/v1/revisions?revision_id=eq.${revision_id}`,
      {
        method: "PATCH",
        headers,
        body: JSON.stringify({
          status: "failed",
          error_message: `Insert failed at batch starting row ${i}`
        })
      }
    );
    return { error: `Insert failed at row ${i}`, details: await insertRes.text() };
  }
}


// ─── STEP 5: Update row count and trigger pipeline ──────────────────────────

bimuploadProgress.setValue(85);

await fetch(
  `${SUPABASE_URL}/rest/v1/revisions?revision_id=eq.${revision_id}`,
  {
    method: "PATCH",
    headers,
    body: JSON.stringify({
      status: "normalizing",
      row_count: rows.length
    })
  }
);

const pipelineResult = await fetch(
  `${SUPABASE_URL}/rest/v1/rpc/run_pipeline`,
  {
    method: "POST",
    headers,
    body: JSON.stringify({ p_revision_id: revision_id })
  }
